#!/usr/bin/env bash
# ASR Qwen3 Evaluation Entrypoint
# Generated by SURE-EVAL Main Flow Agent
# Run ID: main_agent_asr_qwen3_001_1775812307

set -euo pipefail

# Configuration
REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../../../../../.." && pwd)"
MODEL_NAME="asr_qwen3"
MODEL_DIR="$REPO_ROOT/src/sure_eval/models/$MODEL_NAME"
RUN_DIR="$MODEL_DIR/eval_runs/main_agent_asr_qwen3_001"
TOOL_NAME="asr_transcribe"
PYTHON_BIN="$MODEL_DIR/.venv/bin/python"
CONFIG_PATH="$REPO_ROOT/config/default.yaml"

# Run all deterministic scripts from the repository root so config-relative
# paths such as ./data/datasets resolve to the checked-in project data.
cd "$REPO_ROOT"

# Smoke test controls
MAX_SAMPLES="${MAX_SAMPLES:-0}"
SKIP_VALIDATE_AND_EVAL="${SKIP_VALIDATE_AND_EVAL:-0}"

# Datasets to evaluate
DATASETS=("aishell1" "librispeech_clean")

echo "=========================================="
echo "SURE-EVAL: ASR Qwen3 Evaluation"
echo "Run ID: main_agent_asr_qwen3_001_1775812307"
echo "Model: $MODEL_NAME"
echo "Datasets: ${DATASETS[*]}"
echo "=========================================="

# Create run directories
mkdir -p "$RUN_DIR"/{datasets,predictions,evaluation,reports}
mkdir -p "$RUN_DIR/predictions/logs"

print_generation_progress() {
  local dataset="$1"
  local status_file="$RUN_DIR/prediction_generation_status.json"
  while true; do
    if [[ -f "$status_file" ]]; then
      "$PYTHON_BIN" - "$status_file" "$dataset" <<'PY'
import json
import sys
from pathlib import Path

status_path = Path(sys.argv[1])
dataset_name = sys.argv[2]

try:
    payload = json.loads(status_path.read_text(encoding="utf-8"))
except Exception:
    sys.exit(0)

for item in payload.get("datasets", []):
    if item.get("dataset") == dataset_name:
        generated = item.get("num_generated_samples", 0)
        expected = item.get("num_expected_samples", "?")
        status = item.get("status", "unknown")
        print(f"[PROGRESS] {dataset_name}: {generated}/{expected} status={status}", flush=True)
        break
PY
    fi
    sleep 10
  done
}

# Dataset preparation
echo ""
echo "[PHASE 1] Dataset Preparation"
echo "----------------------------"
for dataset in "${DATASETS[@]}"; do
  echo "Preparing dataset: $dataset"
  "$PYTHON_BIN" "$REPO_ROOT/scripts/prepare_sure_dataset.py" \
    --dataset "$dataset" \
    --config "$CONFIG_PATH" \
    --output "$RUN_DIR/datasets/${dataset}_prepare_summary.json" || {
      echo "WARNING: Failed to prepare $dataset, continuing..."
    }
done

# Materialize prediction templates
echo ""
echo "[PHASE 2] Materialize Prediction Templates"
echo "-----------------------------------------"
for dataset in "${DATASETS[@]}"; do
  echo "Creating template for: $dataset"
  "$PYTHON_BIN" "$REPO_ROOT/scripts/materialize_predictions_template.py" \
    --dataset "$dataset" \
    --config "$CONFIG_PATH" \
    --output-dir "$RUN_DIR/predictions" \
    --overwrite \
    --manifest-name "${dataset}_manifest.json" || {
      echo "WARNING: Failed to materialize template for $dataset"
    }
done

# Generate predictions via MCP server
echo ""
echo "[PHASE 3] Generate Predictions (MCP Server)"
echo "------------------------------------------"
echo "Using server: $MODEL_DIR/server.py"
echo "Tool: $TOOL_NAME"

for dataset in "${DATASETS[@]}"; do
  echo ""
  echo "Generating predictions for: $dataset"
  echo "Live predictions log: $RUN_DIR/predictions/logs/${dataset}_results.log"
  GEN_ARGS=(
    --model-dir "$MODEL_DIR"
    --dataset "$dataset"
    --run-dir "$RUN_DIR"
    --tool-name "$TOOL_NAME"
    --config "$CONFIG_PATH"
  )
  
  # Language hint based on dataset
  if [[ "$dataset" == "aishell1" ]]; then
    GEN_ARGS+=(--language "Chinese")
  elif [[ "$dataset" == "librispeech"* ]]; then
    GEN_ARGS+=(--language "English")
  fi
  
  # Bounded smoke test mode
  if [[ "$MAX_SAMPLES" != "0" ]]; then
    GEN_ARGS+=(--max-samples "$MAX_SAMPLES")
    echo "SMOKE TEST MODE: max_samples=$MAX_SAMPLES"
  fi

  print_generation_progress "$dataset" &
  PROGRESS_PID=$!

  "$PYTHON_BIN" "$REPO_ROOT/scripts/generate_predictions_via_server.py" "${GEN_ARGS[@]}" 2>&1 | tee "$RUN_DIR/predictions/logs/${dataset}_generation.log" || {
    kill "$PROGRESS_PID" 2>/dev/null || true
    wait "$PROGRESS_PID" 2>/dev/null || true
    echo "ERROR: Prediction generation failed for $dataset"
    exit 1
  }

  kill "$PROGRESS_PID" 2>/dev/null || true
  wait "$PROGRESS_PID" 2>/dev/null || true
done

# Write prediction generation status
cat > "$RUN_DIR/predictions/prediction_generation_status.json" << EOF
{
  "status": "completed",
  "timestamp": "$(date -Iseconds)",
  "datasets": $(printf '%s\n' "${DATASETS[@]}" | jq -R . | jq -s .),
  "max_samples": $MAX_SAMPLES,
  "run_dir": "$RUN_DIR"
}
EOF

echo ""
echo "Prediction generation completed: $RUN_DIR/predictions/"

# Early exit for smoke test mode
if [[ "$SKIP_VALIDATE_AND_EVAL" == "1" ]]; then
  echo ""
  echo "=========================================="
  echo "SMOKE TEST COMPLETE"
  echo "Skipping validation and evaluation"
  echo "Run directory: $RUN_DIR"
  echo "=========================================="
  exit 0
fi

# Validate predictions
echo ""
echo "[PHASE 4] Validate Predictions"
echo "-----------------------------"
for dataset in "${DATASETS[@]}"; do
  echo "Validating: $dataset"
  "$PYTHON_BIN" "$REPO_ROOT/scripts/validate_prediction_files.py" \
    --dataset "$dataset" \
    --pred-dir "$RUN_DIR/predictions" \
    --require-nonempty \
    --output "$RUN_DIR/validation_${dataset}.json" || {
      echo "ERROR: Validation failed for $dataset"
      exit 1
    }
done

# Evaluate predictions
echo ""
echo "[PHASE 5] Evaluate Predictions"
echo "-----------------------------"
for dataset in "${DATASETS[@]}"; do
  echo "Evaluating: $dataset"
  "$PYTHON_BIN" "$REPO_ROOT/scripts/evaluate_predictions.py" \
    --dataset "$dataset" \
    --pred-dir "$RUN_DIR/predictions" \
    --tool-name "$MODEL_NAME" \
    --output "$RUN_DIR/evaluation/evaluation_${dataset}.json" || {
      echo "ERROR: Evaluation failed for $dataset"
      exit 1
    }
done

# Refresh report snapshot
echo ""
echo "[PHASE 6] Refresh Report Snapshot"
echo "--------------------------------"
"$PYTHON_BIN" "$REPO_ROOT/scripts/refresh_report_snapshot.py" \
  --markdown "$RUN_DIR/reports/report_snapshot.md" \
  --json "$RUN_DIR/reports/report_summary.json" || {
    echo "WARNING: Report refresh failed, continuing..."
  }

# Final summary
echo ""
echo "=========================================="
echo "EVALUATION COMPLETE"
echo "=========================================="
echo "Run directory: $RUN_DIR"
echo ""
echo "Artifacts:"
echo "  - Datasets: $RUN_DIR/datasets/"
echo "  - Predictions: $RUN_DIR/predictions/"
echo "  - Evaluation: $RUN_DIR/evaluation/"
echo "  - Reports: $RUN_DIR/reports/"
echo "=========================================="
